"""
Pytest test suite for MedicationRequest prescribing requirements.

Requirements tested:
  1. A prescribing clinician shall issue a MedicationRequest.
  2. Requests for controlled substances shall require schedule verification.
  3. Boundary cases on timestamps and numeric elements must be tested.
"""

import pytest
from datetime import datetime, timezone, timedelta
from decimal import Decimal
from unittest.mock import MagicMock, patch
import uuid

# ---------------------------------------------------------------------------
# Domain models (minimal stubs – replace with real imports in your project)
# ---------------------------------------------------------------------------

class ScheduleVerificationError(Exception):
    """Raised when a controlled-substance schedule cannot be verified."""


class AuthorizationError(Exception):
    """Raised when the prescriber is not authorised to issue the request."""


class ValidationError(Exception):
    """Raised when a MedicationRequest fails field validation."""


class Prescriber:
    """Represents a clinician who may issue prescriptions."""

    def __init__(
        self,
        prescriber_id: str,
        name: str,
        dea_number: str | None = None,
        is_active_clinician: bool = True,
        license_expiry: datetime | None = None,
    ):
        self.prescriber_id = prescriber_id
        self.name = name
        self.dea_number = dea_number
        self.is_active_clinician = is_active_clinician
        self.license_expiry = license_expiry or (
            datetime.now(timezone.utc) + timedelta(days=365)
        )

    @property
    def license_is_valid(self) -> bool:
        return self.license_expiry > datetime.now(timezone.utc)


class Medication:
    """Represents a medication with optional controlled-substance schedule."""

    VALID_SCHEDULES = {None, "II", "III", "IV", "V"}  # None → not controlled

    def __init__(
        self,
        medication_id: str,
        name: str,
        controlled_schedule: str | None = None,
    ):
        if controlled_schedule not in self.VALID_SCHEDULES:
            raise ValidationError(
                f"Unknown controlled schedule: {controlled_schedule}"
            )
        self.medication_id = medication_id
        self.name = name
        self.controlled_schedule = controlled_schedule

    @property
    def is_controlled(self) -> bool:
        return self.controlled_schedule is not None


class MedicationRequest:
    """
    Core domain object representing a prescription order.

    Rules enforced at construction:
      * prescriber must be an active clinician with a valid licence.
      * authored_on must be a timezone-aware datetime.
      * quantity and days_supply must be positive finite numbers.
      * refills must be >= 0.
      * If the medication is a controlled substance the DEA number on the
        prescriber must be present AND schedule_verified must be True.
    """

    MAX_QUANTITY = Decimal("9999.999")
    MAX_DAYS_SUPPLY = 365
    MAX_REFILLS_CONTROLLED = 0          # Schedule II – no refills
    MAX_REFILLS_NON_CONTROLLED = 11

    def __init__(
        self,
        request_id: str,
        prescriber: Prescriber,
        medication: Medication,
        quantity: Decimal,
        quantity_unit: str,
        days_supply: int,
        authored_on: datetime,
        refills: int = 0,
        schedule_verified: bool = False,
        dose_instructions: str = "",
    ):
        self._validate_prescriber(prescriber)
        self._validate_authored_on(authored_on)
        self._validate_quantity(quantity)
        self._validate_days_supply(days_supply)
        self._validate_refills(refills, medication)
        if medication.is_controlled:
            self._validate_controlled_substance(
                prescriber, medication, schedule_verified
            )

        self.request_id = request_id
        self.prescriber = prescriber
        self.medication = medication
        self.quantity = quantity
        self.quantity_unit = quantity_unit
        self.days_supply = days_supply
        self.authored_on = authored_on
        self.refills = refills
        self.schedule_verified = schedule_verified
        self.dose_instructions = dose_instructions
        self.status = "active"

    # ------------------------------------------------------------------
    # Private validators
    # ------------------------------------------------------------------

    @staticmethod
    def _validate_prescriber(prescriber: Prescriber) -> None:
        if not isinstance(prescriber, Prescriber):
            raise AuthorizationError("prescriber must be a Prescriber instance")
        if not prescriber.is_active_clinician:
            raise AuthorizationError(
                f"Prescriber {prescriber.prescriber_id} is not an active clinician"
            )
        if not prescriber.license_is_valid:
            raise AuthorizationError(
                f"Prescriber {prescriber.prescriber_id} licence has expired"
            )

    @staticmethod
    def _validate_authored_on(authored_on: datetime) -> None:
        if not isinstance(authored_on, datetime):
            raise ValidationError("authored_on must be a datetime object")
        if authored_on.tzinfo is None:
            raise ValidationError("authored_on must be timezone-aware")
        # Must not be more than 1 minute in the future (clock skew tolerance)
        now = datetime.now(timezone.utc)
        if authored_on > now + timedelta(minutes=1):
            raise ValidationError("authored_on must not be a future timestamp")

    @staticmethod
    def _validate_quantity(quantity: Decimal) -> None:
        if not isinstance(quantity, Decimal):
            raise ValidationError("quantity must be a Decimal")
        if quantity <= Decimal("0"):
            raise ValidationError("quantity must be greater than zero")
        if quantity > MedicationRequest.MAX_QUANTITY:
            raise ValidationError(
                f"quantity exceeds maximum {MedicationRequest.MAX_QUANTITY}"
            )

    @staticmethod
    def _validate_days_supply(days_supply: int) -> None:
        if not isinstance(days_supply, int):
            raise ValidationError("days_supply must be an integer")
        if days_supply < 1:
            raise ValidationError("days_supply must be at least 1")
        if days_supply > MedicationRequest.MAX_DAYS_SUPPLY:
            raise ValidationError(
                f"days_supply exceeds maximum {MedicationRequest.MAX_DAYS_SUPPLY}"
            )

    @staticmethod
    def _validate_refills(refills: int, medication: Medication) -> None:
        if not isinstance(refills, int):
            raise ValidationError("refills must be an integer")
        if refills < 0:
            raise ValidationError("refills must be >= 0")
        if medication.is_controlled and medication.controlled_schedule == "II":
            if refills > MedicationRequest.MAX_REFILLS_CONTROLLED:
                raise ValidationError(
                    "Schedule II controlled substances may not have refills"
                )
        elif not medication.is_controlled:
            if refills > MedicationRequest.MAX_REFILLS_NON_CONTROLLED:
                raise ValidationError(
                    f"Non-controlled refills may not exceed "
                    f"{MedicationRequest.MAX_REFILLS_NON_CONTROLLED}"
                )

    @staticmethod
    def _validate_controlled_substance(
        prescriber: Prescriber,
        medication: Medication,
        schedule_verified: bool,
    ) -> None:
        if not prescriber.dea_number:
            raise ScheduleVerificationError(
                f"Prescriber {prescriber.prescriber_id} has no DEA number; "
                f"cannot prescribe Schedule {medication.controlled_schedule}"
            )
        if not schedule_verified:
            raise ScheduleVerificationError(
                f"Schedule {medication.controlled_schedule} verification is "
                f"required for controlled substance {medication.name}"
            )


