def _build_request(
    prescriber: Prescriber,
    medication: Medication,
    authored_on: datetime | None = None,
    quantity: Decimal = Decimal("30"),
    days_supply: int = 30,
    refills: int = 0,
    schedule_verified: bool = False,
    request_id: str | None = None,
) -> MedicationRequest:
    """Helper factory to reduce repetition in tests."""
    return MedicationRequest(
        request_id=request_id or str(uuid.uuid4()),
        prescriber=prescriber,
        medication=medication,
        quantity=quantity,
        quantity_unit="tablets",
        days_supply=days_supply,
        authored_on=authored_on or datetime.now(timezone.utc),
        refills=refills,
        schedule_verified=schedule_verified,
    )


