# 1. Prescribing Clinician Tests
# ===========================================================================

class TestPrescriberAuthorization:
    """Verify that only valid, active clinicians may issue MedicationRequests."""

    def test_valid_prescriber_creates_request(
        self, valid_prescriber, non_controlled_med
    ):
        req = _build_request(valid_prescriber, non_controlled_med)
        assert req.prescriber.prescriber_id == "P-001"
        assert req.status == "active"

    def test_inactive_clinician_raises_authorization_error(
        self, inactive_prescriber, non_controlled_med
    ):
        with pytest.raises(AuthorizationError, match="not an active clinician"):
            _build_request(inactive_prescriber, non_controlled_med)

    def test_expired_license_raises_authorization_error(
        self, expired_license_prescriber, non_controlled_med
    ):
        with pytest.raises(AuthorizationError, match="licence has expired"):
            _build_request(expired_license_prescriber, non_controlled_med)

    def test_non_prescriber_object_raises_authorization_error(
        self, non_controlled_med, now_utc
    ):
        fake_prescriber = MagicMock()
        fake_prescriber.__class__ = object  # not a Prescriber subclass
        with pytest.raises(AuthorizationError):
            MedicationRequest(
                request_id=str(uuid.uuid4()),
                prescriber=fake_prescriber,
                medication=non_controlled_med,
                quantity=Decimal("10"),
                quantity_unit="tablets",
                days_supply=10,
                authored_on=now_utc,
            )

    def test_prescriber_license_expiring_in_one_second_is_still_valid(
        self, non_controlled_med
    ):
        just_valid = Prescriber(
            prescriber_id="P-999",
            name="Dr. About-to-Expire",
            dea_number="AE0000001",
            is_active_clinician=True,
            license_expiry=datetime.now(timezone.utc) + timedelta(seconds=1),
        )
        req = _build_request(just_valid, non_controlled_med)
        assert req.prescriber.license_is_valid is True

    def test_prescriber_license_expired_one_second_ago_is_invalid(self):
        just_expired = Prescriber(
            prescriber_id="P-998",
            name="Dr. Just-Expired",
            dea_number="JE0000001",
            is_active_clinician=True,
            license_expiry=datetime.now(timezone.utc) - timedelta(seconds=1),
        )
        assert just_expired.license_is_valid is False

    def test_request_id_is_stored(self, valid_prescriber, non_controlled_med):
        rid = "REQ-20240101-001"
        req = _build_request(
            valid_prescriber, non_controlled_med, request_id=rid
        )
        assert req.request_id == rid


