class TestControlledSubstanceScheduleVerification:
    """Schedule II–V medications require DEA number and schedule verification."""

    @pytest.mark.parametrize(
        "schedule_fixture",
        [
            "schedule_ii_med",
            "schedule_iii_med",
            "schedule_iv_med",
            "schedule_v_med",
        ],
    )
    def test_controlled_med_without_verification_raises(
        self, request, valid_prescriber, schedule_fixture
    ):
        med = request.getfixturevalue(schedule_fixture)
        with pytest.raises(ScheduleVerificationError, match="verification is required"):
            _build_request(
                valid_prescriber, med, schedule_verified=False
            )

    @pytest.mark.parametrize(
        "schedule_fixture",
        [
            "schedule_ii_med",
            "schedule_iii_med",
            "schedule_iv_med",
            "schedule_v_med",
        ],
    )
    def test_controlled_med_with_verification_succeeds(
        self, request, valid_prescriber, schedule_fixture
    ):
        med = request.getfixturevalue(schedule_fixture)
        req = _build_request(
            valid_prescriber, med, schedule_verified=True
        )
        assert req.schedule_verified is True
        assert req.medication.is_controlled is True

    def test_non_controlled_med_does_not_require_verification(
        self, valid_prescriber, non_controlled_med
    ):
        req = _build_request(
            valid_prescriber, non_controlled_med, schedule_verified=False
        )
        assert req.medication.is_controlled is False

    def test_controlled_med_without_dea_number_raises(
        self, prescriber_without_dea, schedule_ii_med
    ):
        with pytest.raises(ScheduleVerificationError, match="no DEA number"):
            _build_request(
                prescriber_without_dea,
                schedule_ii_med,
                schedule_verified=True,
            )

    def test_schedule_ii_allows_zero_refills(
        self, valid_prescriber, schedule_ii_med
    ):
        req = _build_request(
            valid_prescriber,
            schedule_ii_med,
            schedule_verified=True,
            refills=0,
        )
        assert req.refills == 0

    def test_schedule_ii_rejects_any_refills(
        self, valid_prescriber, schedule_ii_med
    ):
        with pytest.raises(ValidationError, match="may not have refills"):
            _build_request(
                valid_prescriber,
                schedule_ii_med,
                schedule_verified=True,
                refills=1,
            )

    def test_schedule_iii_allows_refills_when_verified(
        self, valid_prescriber, schedule_iii_med
    ):
        req = _build_request(
            valid_prescriber,
            schedule_iii_med,
            schedule_verified=True,
            refills=5,
        )
        assert req.refills == 5

    def test_unknown_controlled_schedule_raises_on_medication_creation(self):
        with pytest.raises(ValidationError, match="Unknown controlled schedule"):
            Medication(
                medication_id="M-BAD",
                name="Unknown",
                controlled_schedule="I",  # Schedule I – not prescribable
            )

    def test_verification_flag_stored_correctly(
        self, valid_prescriber, schedule_iv_med
    ):
        req = _build_request(
            valid_prescriber, schedule_iv_med, schedule_verified=True
        )
        assert req.schedule_verified is True
        assert req.medication.controlled_schedule == "IV"


