class TestTimestampBoundaries:
    """authored_on must be timezone-aware and not in the future."""

    def test_authored_on_exactly_now_is_accepted(self, valid_prescriber, non_controlled_med):
        now = datetime.now(timezone.utc)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=now
        )
        assert req.authored_on == now

    def test_authored_on_one_second_ago_is_accepted(
        self, valid_prescriber, non_controlled_med
    ):
        authored = datetime.now(timezone.utc) - timedelta(seconds=1)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=authored
        )
        assert req.authored_on == authored

    def test_authored_on_within_clock_skew_tolerance_is_accepted(
        self, valid_prescriber, non_controlled_med
    ):
        """Up to 60 s in the future is allowed (clock-skew tolerance)."""
        authored = datetime.now(timezone.utc) + timedelta(seconds=59)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=authored
        )
        assert req.authored_on is not None

    def test_authored_on_one_second_past_tolerance_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        authored = datetime.now(timezone.utc) + timedelta(seconds=62)
        with pytest.raises(ValidationError, match="future timestamp"):
            _build_request(
                valid_prescriber, non_controlled_med, authored_on=authored
            )

    def test_authored_on_naive_datetime_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        naive = datetime.utcnow()  # no tzinfo
        with pytest.raises(ValidationError, match="timezone-aware"):
            _build_request(
                valid_prescriber, non_controlled_med, authored_on=naive
            )

    def test_authored_on_non_datetime_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        with pytest.raises(ValidationError, match="must be a datetime"):
            _build_request(
                valid_prescriber,
                non_controlled_med,
                authored_on="2024-01-01T00:00:00Z",  # type: ignore[arg-type]
            )

    def test_authored_on_very_old_date_is_accepted(
        self, valid_prescriber, non_controlled_med
    ):
        """Historical orders (e.g., data migration) should not be blocked."""
        old = datetime(1990, 1, 1, tzinfo=timezone.utc)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=old
        )
        assert req.authored_on.year == 1990

    def test_authored_on_with_positive_utc_offset_is_accepted(
        self, valid_prescriber, non_controlled_med
    ):
        tz_plus5 = timezone(timedelta(hours=5))
        authored = datetime.now(tz_plus5) - timedelta(minutes=10)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=authored
        )
        assert req.authored_on.tzinfo is not None

    def test_authored_on_with_negative_utc_offset_is_accepted(
        self, valid_prescriber, non_controlled_med
    ):
        tz_minus8 = timezone(timedelta(hours=-8))
        authored = datetime.now(tz_minus8) - timedelta(minutes=5)
        req = _build_request(
            valid_prescriber, non_controlled_med, authored_on=authored
        )
        assert req.authored_on.tzinfo is not None


