class TestQuantityBoundaries:
    """quantity must be a positive Decimal within the allowed range."""

    def test_minimum_valid_quantity(self, valid_prescriber, non_controlled_med):
        req = _build_request(
            valid_prescriber,
            non_controlled_med,
            quantity=Decimal("0.001"),
        )
        assert req.quantity == Decimal("0.001")

    def test_quantity_of_zero_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        with pytest.raises(ValidationError, match="greater than zero"):
            _build_request(
                valid_prescriber, non_controlled_med, quantity=Decimal("0")
            )

    def test_negative_quantity_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        with pytest.raises(ValidationError, match="greater than zero"):
            _build_request(
                valid_prescriber,
                non_controlled_med,
                quantity=Decimal("-1"),
            )

    def test_maximum_valid_quantity(self, valid_prescriber, non_controlled_med):
        req = _build_request(
            valid_prescriber,
            non_controlled_med,
            quantity=MedicationRequest.MAX_QUANTITY,
        )
        assert req.quantity == MedicationRequest.MAX_QUANTITY

    def test_quantity_one_above_maximum_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        over_max = MedicationRequest.MAX_QUANTITY + Decimal("0.001")
        with pytest.raises(ValidationError, match="exceeds maximum"):
            _build_request(
                valid_prescriber, non_controlled_med, quantity=over_max
            )

    def test_quantity_as_float_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        with pytest.raises(ValidationError, match="must be a Decimal"):
            _build_request(
                valid_prescriber,
                non_controlled_med,
                quantity=30.0,  # type: ignore[arg-type]
            )

    def test_quantity_as_integer_is_rejected(
        self, valid_prescriber, non_controlled_med
    ):
        with pytest.raises(ValidationError, match="must be a Decimal"):
            _build_request(
                valid_prescriber,
                non_controlled_med,
                quantity=30,  # type: ignore[arg-type]
            )

    @pytest.mark.parametrize(
        "qty",
        [Decimal("1"), Decimal("30"), Decimal("100"), Decimal("9999.999")],
    )
    def test_typical_valid_quantities(
        self, valid_prescriber, non_controlled_med, qty
    ):
        req = _build_request(
            valid_prescriber, non_controlled_med, quantity=qty
        )
        assert req.quantity == qty


