class TestRefillBoundaries:
    """Refills must be non-negative and within medication-class limits."""

    def test_zero_refills_always_allowed(
        self, valid_prescriber, non_controlled_med
    ):
        req = _build_request(
            valid_prescriber, non_controlled_med, refills=0
